const brand = $.input.brandName;
const pillars = $.input.contentPillars || 'educational, behind-the-scenes, promotional';
const query = 'Instagram content strategy trends and best performing post types for ' + brand + ' ' + pillars;
return { query };

const results = $.steps.searchTrends.response.results || [];
let research = '';
results.forEach((r, i) => {
  research += (i + 1) + '. ' + (r.title || '') + '\n   ' + (r.text || '').slice(0, 800) + '\n\n';
});
return { research, sourceCount: results.length };

const research = $.steps.compileResearch.output;
const brand = $.input.brandName;
const pillars = $.input.contentPillars || 'educational, behind-the-scenes, promotional, community, entertaining';
const postsPerWeek = $.input.postsPerWeek || 5;
const audience = $.input.targetAudience || 'general audience';

let prompt = 'You are an Instagram content strategist for the brand "' + brand + '". Create a comprehensive content schedule for the next 2 weeks.\n\n';
prompt += 'BRAND: ' + brand + '\n';
prompt += 'TARGET AUDIENCE: ' + audience + '\n';
prompt += 'CONTENT PILLARS: ' + pillars + '\n';
prompt += 'POSTS PER WEEK: ' + postsPerWeek + '\n\n';
prompt += 'TREND RESEARCH (' + research.sourceCount + ' sources):\n';
prompt += research.research + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Create ' + (postsPerWeek * 2) + ' post ideas for 2 weeks\n';
prompt += '- Distribute content across the pillars\n';
prompt += '- Include: post type (reel, carousel, single, story), caption, visual direction, hashtags\n';
prompt += '- Suggest best posting time for each post\n';
prompt += '- Include a CTA in each caption\n';
prompt += '- Mix trending topics with evergreen content\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "schedule": [\n';
prompt += '    {\n';
prompt += '      "week": 1,\n';
prompt += '      "day": "Monday",\n';
prompt += '      "postType": "reel|carousel|single|story",\n';
prompt += '      "pillar": "educational",\n';
prompt += '      "topic": "post topic",\n';
prompt += '      "caption": "full caption with CTA",\n';
prompt += '      "visualDirection": "what the image/video should show",\n';
prompt += '      "hashtags": ["tag1", "tag2"],\n';
prompt += '      "postingTime": "9:00 AM",\n';
prompt += '      "engagementTip": "how to boost engagement"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "strategyOverview": "2-week content strategy summary",\n';
prompt += '  "hashtagStrategy": "branded and niche hashtag recommendations",\n';
prompt += '  "engagementTips": ["general engagement tips"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { schedule: [], strategyOverview: raw, hashtagStrategy: '', engagementTips: [] }; }

const ai = $.steps.parseAI.output;
const rows = [];
rows.push(['Week', 'Day', 'Post Type', 'Pillar', 'Topic', 'Caption', 'Visual Direction', 'Hashtags', 'Posting Time', 'Engagement Tip', 'Status']);
(ai.schedule || []).forEach(s => {
  rows.push([String(s.week || ''), s.day || '', s.postType || '', s.pillar || '', s.topic || '', (s.caption || '').slice(0, 1500), s.visualDirection || '', (s.hashtags || []).join(', '), s.postingTime || '', s.engagementTip || '', 'Scheduled']);
});
return { rows, postCount: rows.length - 1 };

const ai = $.steps.parseAI.output;
const posts = $.steps.buildSheetRows.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Instagram Content Schedule Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Brand:* ' + $.input.brandName + ' | *Posts Scheduled:* ' + posts.postCount + ' over 2 weeks' } });
blocks.push({ type: 'divider' });

if (ai.strategyOverview) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Strategy:* ' + ai.strategyOverview.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

(ai.schedule || []).slice(0, 5).forEach((s, i) => {
  let text = '*W' + s.week + ' ' + s.day + '* - _' + s.postType + '_ [' + s.pillar + ']\n';
  text += s.topic + '\n';
  text += '_' + s.postingTime + '_';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 500) } });
});
if ((ai.schedule || []).length > 5) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_...and ' + ((ai.schedule || []).length - 5) + ' more posts in Google Sheets_' } });
}

if (ai.hashtagStrategy) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Hashtag Strategy:* ' + ai.hashtagStrategy.slice(0, 500) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Schedule saved to Google Sheets | Powered by Exa + Claude AI' }] });
const fallback = 'IG Schedule: ' + posts.postCount + ' posts for ' + $.input.brandName;
return { blocks, fallback };
